export const checkId = 'database-config';
export const name = 'Database Configuration';
export const appliesTo = ['deployable', 'server', 'framework'];

const DB_DEPS = [
  'mongoose', 'sequelize', 'prisma', '@prisma/client', 'typeorm', 'knex',
  'drizzle-orm', 'drizzle-kit', 'kysely', '@astrojs/db', 'objection', 'bookshelf',
  'mikro-orm', '@mikro-orm/core', 'waterline', 'slonik', 'zapatos', '@databases/pg',
  'pg', 'postgres', 'mysql2', 'mysql', 'mongodb', 'redis', 'ioredis',
  '@upstash/redis', '@upstash/postgres', '@planetscale/database', '@vercel/postgres',
  '@vercel/kv', '@neondatabase/serverless', 'neon', '@libsql/client', 'libsql',
  'better-sqlite3', 'sqlite3', 'node-sqlite', 'sql.js', 'turso',
  'tedious', 'oracledb',
  'wrangler', '@cloudflare/workers-types', 'bun-sql', 'denodb', 'dexie',
  'pouchdb', 'rxdb', 'firebase', '@google-cloud/firestore',
];

const DB_DEP_SUBSTRINGS = [
  'supabase', 'drizzle', 'prisma', 'planetscale', 'neon', 'libsql', 'turso', 'upstash'
];

const GOOD_PATTERNS = [
  /(?:process\.env|Bun\.env|import\.meta\.env)\.[A-Z_]*(?:DATABASE|DB|POSTGRES|POSTGRESQL|MONGO|MONGODB|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1|UPSTASH|ASTRO_DB|ASTRO_DATABASE|DIRECT_URL|SHADOW_DATABASE)[A-Z_]*/i,
  /Deno\.env\.get\s*\(\s*["'][^"']*(?:DATABASE|DB|POSTGRES|MONGO|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1|ASTRO_DATABASE)[^"']*["']\s*\)/i,
  /env\s*\(\s*["'][^"']*(?:DATABASE|DB|POSTGRES|MONGO|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1)[^"']*["']\s*\)/i,
  /env\.[A-Z_]*(?:DATABASE|DB|POSTGRES|MONGO|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1|UPSTASH|ASTRO_DATABASE)[A-Z_]*/i,
  /\$\{(?:DATABASE|DB|POSTGRES|MONGO|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1|ASTRO_DATABASE)[A-Z_]*\}/i,
  /^(?:DATABASE|DB|POSTGRES|MONGO|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1|UPSTASH|ASTRO_DB|ASTRO_DATABASE)[A-Z_]*=/im,
  /binding\s*=\s*["']DB["']/i,
  /dbCredentials\s*:\s*\{[^}]*(?:process\.env|env\.|Deno\.env)/i,
  /astro\s*\.\s*db\s*\(/i,
  /defineDb\s*\(/i,
  /\[\[(d1_databases|env\.[a-z]+\.d1_databases)\]\]/im,
];

const BAD_PATTERNS = [
  /(?:mongodb|mongodb\+srv|postgres|postgresql|mysql|redis):\/\/[^:]+:[^@\s]+@\S+/i,
  /mysql:\/\/\w+:\w+@\w+/i,
  /postgres(?:ql)?:\/\/\w+:[^@\s]+@\w+/i,
];

const STRONG_PATH_RE = [
  /(^|[\/])(db|database|model|schema|migration|seed)s?[\/]/i,
  /(^|[\/])prisma[\/]/i,
  /(^|[\/])drizzle[\/]/i,
  /(^|[\/])packages[\/][^\/]*db[^\/]*[\/]/i,
  /(^|[\/])apps[\/][^\/]*[\/](db|database|prisma|drizzle)[\/]/i,
  /(^|[\/])(?:config|configs)[\/](?:db|database|mongo|postgres|mysql|redis|sqlite|drizzle|prisma)/i,
  /(^|[\/])[^\/]*(?:db|database|mongo|postgres|mysql|redis|sqlite|drizzle|prisma|schema|migration)\.(js|ts|mjs|cjs|prisma|toml)$/i,
];

const CONFIG_FILES_RE = [
  /(^|[\/])drizzle\.config\./i,
  /(^|[\/])wrangler\.toml$/i,
  /(^|[\/])prisma[\/][^\/]*\.prisma$/i,
  /(^|[\/])astro\.config\./i,
  /(^|[\/])nuxt\.config\./i,
  /(^|[\/])nitro\.config\./i,
  /(^|[\/])next\.config\./i,
  /(^|[\/])\.env/i,
  /(^|[\/])docker-compose/i,
  /(^|[\/])compose\.ya?ml$/i,
];

function isDbDriverLibrary(packageJson) {
  if (!packageJson?.name) return false;
  const n = packageJson.name;
  if (DB_DEPS.includes(n)) return true;
  if (DB_DEP_SUBSTRINGS.some(s => n.includes(s))) return true;
  if (n.startsWith('@')) {
    const base = n.split('/')[1];
    if (base && (DB_DEPS.includes(base) || DB_DEP_SUBSTRINGS.some(s => base.includes(s)))) return true;
  }
  return false;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (repoType === 'empty' || (tree.length <= 1 && !packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repo — no DB config needed', findings: [] };
    }

    if (isDbDriverLibrary(packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: `DB driver library (${packageJson.name}) — not applicable`, findings: [] };
    }

    const pkgPaths = tree.filter(p => 
      p.endsWith('package.json') && 
      !/node_modules|\.git/.test(p)
    );

    let hasDbDep = false;
    const dbDepLocations = [];
    const dbScriptsFound = [];

    for (const p of pkgPaths.slice(0, 40)) {
      const content = await files.get(p);
      if (!content) continue;
      let pkg;
      try {
        pkg = JSON.parse(content);
      } catch {
        continue;
      }
      const deps = { ...pkg.dependencies, ...pkg.devDependencies };
      const foundDeps = Object.keys(deps).filter(d => 
        DB_DEPS.includes(d) || DB_DEP_SUBSTRINGS.some(s => d.includes(s))
      );
      if (foundDeps.length) {
        hasDbDep = true;
        dbDepLocations.push({ path: p, deps: foundDeps });
      }
      const scripts = pkg.scripts || {};
      for (const [name, cmd] of Object.entries(scripts)) {
        if (/\b(db|database|prisma|drizzle|migrate|seed|pg|mysql|mongo|redis|sqlite|turso|supabase|planetscale|neon|d1):?\b/i.test(name + ' ' + cmd)) {
          dbScriptsFound.push({ path: p, script: name });
          break;
        }
      }
    }

    if (packageJson && !pkgPaths.some(p => p === 'package.json' || p === './package.json')) {
      const rootDeps = { ...packageJson.dependencies, ...packageJson.devDependencies };
      const foundDeps = Object.keys(rootDeps).filter(d => 
        DB_DEPS.includes(d) || DB_DEP_SUBSTRINGS.some(s => d.includes(s))
      );
      if (foundDeps.length) {
        hasDbDep = true;
        dbDepLocations.push({ path: 'package.json', deps: foundDeps });
      }
      const scripts = packageJson.scripts || {};
      for (const [name, cmd] of Object.entries(scripts)) {
        if (/\b(db|database|prisma|drizzle|migrate|seed|pg|mysql|mongo|redis|sqlite|turso|supabase|planetscale|neon|d1):?\b/i.test(name + ' ' + cmd)) {
          dbScriptsFound.push({ path: 'package.json', script: name });
          break;
        }
      }
    }

    const strongFileMatches = tree.filter(p => {
      if (/node_modules|\.git/.test(p)) return false;
      if (/(test|spec|__tests__|__mocks__|examples?|docs|fixtures|dist|build|\.d\.ts)[\/]/i.test(p)) return false;
      return STRONG_PATH_RE.some(re => re.test(p));
    });

    const configFileMatches = tree.filter(p => {
      if (/node_modules|\.git/.test(p)) return false;
      return CONFIG_FILES_RE.some(re => re.test(p));
    });

    const hasDbArtifacts = strongFileMatches.length > 0 || configFileMatches.length > 0;

    if (!hasDbDep && !hasDbArtifacts && dbScriptsFound.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'No database dependency or DB-related files found', findings: [] };
    }

    const toScan = new Set();

    configFileMatches.slice(0, 30).forEach(p => toScan.add(p));
    strongFileMatches.slice(0, 40).forEach(p => toScan.add(p));
    dbDepLocations.slice(0, 15).forEach(loc => toScan.add(loc.path));
    dbScriptsFound.slice(0, 10).forEach(s => toScan.add(s.path));

    if (toScan.size < 50) {
      const dbRelatedDirs = new Set();
      for (const p of [...strongFileMatches, ...configFileMatches]) {
        const lastSlash = p.lastIndexOf('/');
        if (lastSlash > 0) dbRelatedDirs.add(p.substring(0, lastSlash));
      }
      const extraSource = tree.filter(p => {
        if (toScan.has(p)) return false;
        if (!/\.(js|ts|mjs|cjs)$/.test(p)) return false;
        if (/node_modules|\.git/.test(p)) return false;
        if (/(test|spec|__tests__|__mocks__|examples?|dist|build|\.d\.ts)[\/]/i.test(p)) return false;
        for (const d of dbRelatedDirs) {
          if (p.startsWith(d + '/')) return true;
        }
        return /(^|[\/])(src|app|lib|server|api|plugins|routes|middleware|db|database|prisma|drizzle)[\/]/i.test(p);
      }).slice(0, 30);
      extraSource.forEach(p => toScan.add(p));
    }

    const sourceFiles = Array.from(toScan).slice(0, 100);

    let foundGood = false;
    let foundBad = false;
    const findings = [];

    function addFinding(file, line, issue) {
      if (findings.length >= 20) return;
      const f = { file, issue };
      if (line != null) f.line = line;
      findings.push(f);
    }

    for (const filePath of sourceFiles) {
      const content = await files.get(filePath);
      if (!content) continue;

      const lines = content.split('\n');

      for (const pattern of GOOD_PATTERNS) {
        if (!pattern.test(content)) continue;
        foundGood = true;
        let added = false;
        for (let i = 0; i < lines.length; i++) {
          if (pattern.test(lines[i])) {
            addFinding(filePath, i + 1, 'DB config uses environment variables');
            added = true;
            break;
          }
        }
        if (!added) {
          addFinding(filePath, undefined, 'DB config uses environment variables');
        }
      }

      const isTemplate = /(^|[\/])\.env\./i.test(filePath) || /(^|[\/])\.env\.example$/i.test(filePath);
      const isDockerCompose = /docker-compose|compose\./i.test(filePath);
      if (!isTemplate && !isDockerCompose) {
        for (const pattern of BAD_PATTERNS) {
          const re = new RegExp(pattern.source, 'gmi');
          let match;
          let count = 0;
          while ((match = re.exec(content)) !== null && count < 3) {
            count++;
            foundBad = true;
            const snippet = match[0].substring(0, 50);
            for (let i = 0; i < lines.length; i++) {
              if (lines[i].includes(snippet)) {
                addFinding(filePath, i + 1, 'Hardcoded DB connection string with credentials');
                break;
              }
            }
          }
        }
      }
    }

    if (foundBad) {
      return { checkId, status: 'fail', confidence: 'high', message: 'Hardcoded DB credentials detected', findings };
    }
    if (foundGood) {
      return { checkId, status: 'pass', confidence: 'high', message: 'DB configured with environment variables', findings };
    }

    for (const loc of dbDepLocations.slice(0, 5)) {
      addFinding(loc.path, 1, `Database dependency detected: ${loc.deps.join(', ')}`);
    }
    for (const s of dbScriptsFound.slice(0, 5)) {
      addFinding(s.path, 1, `DB-related script detected: ${s.script}`);
    }
    for (const f of strongFileMatches.slice(0, 5)) {
      addFinding(f, undefined, 'Database-related file path detected');
    }
    for (const f of configFileMatches.slice(0, 5)) {
      addFinding(f, undefined, 'Database config file detected');
    }

    if (hasDbDep || dbScriptsFound.length > 0) {
      return { checkId, status: 'check-it', confidence: 'medium', message: 'DB dependency found but could not verify env-based configuration in scanned files', findings };
    }
    return { checkId, status: 'check-it', confidence: 'low', message: 'Database artifacts found but could not determine configuration', findings };

  } catch (err) {
    console.error(`[database-config] error:`, err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Error: ${err.message}`, findings: [] };
  }
}
